    if (current_strategy == Strategy::GED) {
        P_VERTS_PERM_QUERY.resize(N_ACTUAL);
        CANON_P_PERM.resize(N_ACTUAL);

        if (N_ACTUAL == 6) {
            available_canonical_masks = PRECOMPUTED_CANONICAL_MASKS_N6;
        } else {
            std::set<uint16_t> unique_masks;
            if (L_ACTUAL > 0) {
                for (unsigned int i = 0; i < (1U << L_ACTUAL); ++i) {
                    unique_masks.insert(get_canonical_mask(static_cast<uint16_t>(i)));
                }
            } else {
                unique_masks.insert(0);
            }
            available_canonical_masks.assign(unique_masks.begin(), unique_masks.end());
        }

        int num_isos = available_canonical_masks.size();
        mask_to_idx_map.clear();
        for (int i = 0; i < num_isos; ++i) mask_to_idx_map[available_canonical_masks[i]] = i;

        if (num_isos > 0) {
            all_pairwise_ged_cache.assign(num_isos, std::vector<int>(num_isos, 0));
            bool graph_i_adj[N_MAX_GED_CAP][N_MAX_GED_CAP];
            std::array<std::array<bool, N_MAX_GED_CAP>, N_MAX_GED_CAP> graph_j_adj;

            for (int i = 0; i < num_isos; ++i) {
                mask_to_adj_matrix_small_N(available_canonical_masks[i], N_ACTUAL, graph_i_adj);
                for (int r = 0; r < N_ACTUAL; ++r)
                    for (int c = 0; c < N_ACTUAL; ++c)
                        CURRENT_GRAPH_ADJ_QUERY[r][c] = graph_i_adj[r][c];

                for (int j = i + 1; j < num_isos; ++j) {
                    bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
                    mask_to_adj_matrix_small_N(available_canonical_masks[j], N_ACTUAL, tmp);
                    for (int r = 0; r < N_ACTUAL; ++r)
                        for (int c = 0; c < N_ACTUAL; ++c)
                            graph_j_adj[r][c] = tmp[r][c];
                    all_pairwise_ged_cache[i][j] = all_pairwise_ged_cache[j][i] =
                        min_edit_distance_global_perm_small_N(graph_j_adj);
                }
            }
        }

        // Greedy selection maximizing minimum pairwise GED
        chosen_mask_indices_greedy.clear();
        std::vector<bool> is_chosen(num_isos, false);

        if (num_isos > 0) {
            if (mask_to_idx_map.count(0)) {
                int idx = mask_to_idx_map[0];
                chosen_mask_indices_greedy.push_back(idx);
                is_chosen[idx] = true;
            }
            if (L_ACTUAL > 0 && (int)chosen_mask_indices_greedy.size() < M) {
                uint16_t complete = (1U << L_ACTUAL) - 1;
                uint16_t canon_complete = get_canonical_mask(complete);
                if (mask_to_idx_map.count(canon_complete)) {
                    int idx = mask_to_idx_map[canon_complete];
                    if (!is_chosen[idx]) {
                        chosen_mask_indices_greedy.push_back(idx);
                        is_chosen[idx] = true;
                    }
                }
            }
        }

        while ((int)chosen_mask_indices_greedy.size() < M && (int)chosen_mask_indices_greedy.size() < num_isos) {
            int best_idx = -1;
            int best_min_dist = -1;
            for (int c = 0; c < num_isos; ++c) {
                if (is_chosen[c]) continue;
                int min_dist = L_ACTUAL + 1;
                for (int ch : chosen_mask_indices_greedy) {
                    min_dist = std::min(min_dist, all_pairwise_ged_cache[c][ch]);
                }
                if (min_dist > best_min_dist) {
                    best_min_dist = min_dist;
                    best_idx = c;
                }
            }
            if (best_idx == -1) break;
            chosen_mask_indices_greedy.push_back(best_idx);
            is_chosen[best_idx] = true;
        }

        // Fill remaining with duplicates if needed
        while ((int)chosen_mask_indices_greedy.size() < M) {
            chosen_mask_indices_greedy.push_back(chosen_mask_indices_greedy.empty() ? 0 : chosen_mask_indices_greedy[0]);
        }

        G_ADJS_CHOSEN_GED.resize(M);
        for (int k = 0; k < M; ++k) {
            uint16_t mask = 0;
            if (k < (int)chosen_mask_indices_greedy.size() &&
                chosen_mask_indices_greedy[k] < (int)available_canonical_masks.size()) {
                mask = available_canonical_masks[chosen_mask_indices_greedy[k]];
            }
            bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(mask, N_ACTUAL, tmp);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    G_ADJS_CHOSEN_GED[k][r][c] = tmp[r][c];

            std::string s = "";
            for (int b = 0; b < L_ACTUAL; ++b)
                s += ((mask >> b) & 1) ? '1' : '0';
            std::cout << s << "\n";
        }

    } else {
        // DEGREE_RANK strategy
        G_ADJ_LARGE.resize(M);
        G_DEG_LARGE.resize(M);
        G_DEG_ORDER_LARGE.resize(M);

        // Generate M graphs with evenly-spaced edge counts
        std::vector<int> target_edges(M);
        if (M == 1) {
            target_edges[0] = L_ACTUAL / 2;
        } else {
            for (int k = 0; k < M; ++k) {
                target_edges[k] = (int)std::round((double)k * L_ACTUAL / (M - 1.0));
            }
            // Ensure strictly increasing
            for (int k = 1; k < M; ++k) {
                target_edges[k] = std::max(target_edges[k], target_edges[k-1] + 1);
            }
            // Clamp
            for (int k = 0; k < M; ++k) {
                target_edges[k] = std::max(0, std::min(L_ACTUAL, target_edges[k]));
            }
            // Re-enforce monotonicity after clamping
            for (int k = 1; k < M; ++k) {
                target_edges[k] = std::max(target_edges[k], target_edges[k-1] + 1);
            }
            for (int k = 0; k < M; ++k) {
                target_edges[k] = std::min(L_ACTUAL, target_edges[k]);
            }
        }

        for (int k = 0; k < M; ++k) {
            int E = target_edges[k];
            G_ADJ_LARGE[k].assign(L_ACTUAL, false);

            // Generate random graph with exactly E edges
            std::vector<int> positions(L_ACTUAL);
            std::iota(positions.begin(), positions.end(), 0);
            std::shuffle(positions.begin(), positions.end(), RND_ENGINE);
            for (int i = 0; i < E; ++i) {
                G_ADJ_LARGE[k][positions[i]] = true;
            }

            // Compute degrees
            G_DEG_LARGE[k].assign(N_ACTUAL, 0);
            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    if (G_ADJ_LARGE[k][idx]) {
                        G_DEG_LARGE[k][i]++;
                        G_DEG_LARGE[k][j]++;
                    }
                    idx++;
                }
            }

            // Sort vertices by degree (decreasing), break ties by vertex index
            G_DEG_ORDER_LARGE[k].resize(N_ACTUAL);
            std::iota(G_DEG_ORDER_LARGE[k].begin(), G_DEG_ORDER_LARGE[k].end(), 0);
            std::sort(G_DEG_ORDER_LARGE[k].begin(), G_DEG_ORDER_LARGE[k].end(),
                [&](int a, int b) {
                    if (G_DEG_LARGE[k][a] != G_DEG_LARGE[k][b])
                        return G_DEG_LARGE[k][a] > G_DEG_LARGE[k][b];
                    return a < b;
                });

            // Output graph string
            std::string s(L_ACTUAL, '0');
            for (int i = 0; i < L_ACTUAL; ++i) {
