            }
            std::cout << s << "\n";
        }
    }
    std::cout.flush();

    // Query phase
    for (int q = 0; q < 100; ++q) {
        std::string h_str;
        std::cin >> h_str;

        if (current_strategy == Strategy::GED) {
            string_to_adj_matrix_query(h_str, N_ACTUAL);
            int best_j = 0;
            int min_dist = L_ACTUAL + 1;
            for (int j = 0; j < M; ++j) {
                int d = min_edit_distance_global_perm_small_N(G_ADJS_CHOSEN_GED[j]);
                if (d < min_dist) {
                    min_dist = d;
                    best_j = j;
                }
                if (min_dist == 0) break;
            }
            std::cout << best_j << "\n";

        } else {
            // DEGREE_RANK strategy
            string_to_adj_matrix_query(h_str, N_ACTUAL);

            // Compute degrees of H
            std::vector<int> h_deg(N_ACTUAL, 0);
            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                for (int j = i + 1; j < N_ACTUAL; ++j) {
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) {
                        h_deg[i]++;
                        h_deg[j]++;
                    }
                    idx++;
                }
            }

            // Sort H vertices by degree (decreasing)
            std::vector<int> h_order(N_ACTUAL);
            std::iota(h_order.begin(), h_order.end(), 0);
            std::sort(h_order.begin(), h_order.end(),
                [&](int a, int b) {
                    if (h_deg[a] != h_deg[b]) return h_deg[a] > h_deg[b];
                    return a < b;
                });

            // For each graph G_j, compute Hamming distance under degree-rank permutation
            int best_j = 0;
            int min_hamming = L_ACTUAL + 1;

            // Store top candidates for local search refinement
            std::vector<std::pair<int, int>> candidates; // (hamming, j)

            for (int j = 0; j < M; ++j) {
                // Build permutation: G_j's vertex at rank r maps to H's vertex at rank r
                // perm[g_vertex] = h_vertex
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r) {
                    perm[G_DEG_ORDER_LARGE[j][r]] = h_order[r];
                }

                int ham = compute_hamming_under_perm(G_ADJ_LARGE[j], perm, N_ACTUAL);
                candidates.push_back({ham, j});

                if (ham < min_hamming) {
                    min_hamming = ham;
                    best_j = j;
                }
            }

            // Local search on top candidates
            std::sort(candidates.begin(), candidates.end());
            int num_refine = std::min(5, (int)candidates.size());

            for (int ci = 0; ci < num_refine; ++ci) {
                int j = candidates[ci].second;

                // Rebuild permutation
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r) {
                    perm[G_DEG_ORDER_LARGE[j][r]] = h_order[r];
                }

                int cur_ham = candidates[ci].first;

                // Local search: try swaps to improve
                bool improved = true;
                int max_passes = 3;
                while (improved && max_passes-- > 0) {
                    improved = false;
                    for (int a = 0; a < N_ACTUAL && !improved; ++a) {
                        for (int b = a + 1; b < N_ACTUAL; ++b) {
                            int delta = compute_swap_delta(G_ADJ_LARGE[j], perm, a, b, N_ACTUAL);
                            if (delta < 0) {
                                std::swap(perm[a], perm[b]);
                                cur_ham += delta;
                                improved = true;
                                break;
                            }
                        }
                    }
                }

                if (cur_ham < min_hamming) {
                    min_hamming = cur_ham;
                    best_j = j;
                }
            }

            std::cout << best_j << "\n";
        }
        std::cout.flush();
    }

    return 0;
}
