        for (int j = i + 1; j < N; ++j) {
            bool h_edge = CURRENT_GRAPH_ADJ_QUERY[perm[i]][perm[j]];
            if (h_edge != g_adj[idx]) hamming++;
            idx++;
        }
    }
    return hamming;
}

int compute_swap_delta(const std::vector<bool>& g_adj, const std::vector<int>& perm, int a, int b, int N) {
    int delta = 0;
    int pa = perm[a], pb = perm[b];
    for (int x = 0; x < N; ++x) {
