        bool h_before_bx = CURRENT_GRAPH_ADJ_QUERY[pb][px];
        bool h_after_bx = CURRENT_GRAPH_ADJ_QUERY[pa][px];
        delta += (h_after_bx != g_edge_bx) - (h_before_bx != g_edge_bx);
