        if (num_isos > 0 && mask_to_idx_map.count(0)) {
            int idx = mask_to_idx_map[0];
            chosen_mask_indices_greedy.push_back(idx);
            is_chosen[idx] = true;
        }
        if (L_ACTUAL > 0 && (int)chosen_mask_indices_greedy.size() < M) {
            uint16_t complete = (1U << L_ACTUAL) - 1;
            uint16_t canon = get_canonical_mask(complete);
            if (mask_to_idx_map.count(canon)) {
                int idx = mask_to_idx_map[canon];
                if (!is_chosen[idx]) {
                    chosen_mask_indices_greedy.push_back(idx);
                    is_chosen[idx] = true;
                }
            }
        }
        while ((int)chosen_mask_indices_greedy.size() < M && (int)chosen_mask_indices_greedy.size() < num_isos) {
            int best_idx = -1, best_min_dist = -1;
            for (int c = 0; c < num_isos; ++c) {
                if (is_chosen[c]) continue;
                int min_d = L_ACTUAL + 1;
                for (int ch : chosen_mask_indices_greedy)
                    min_d = std::min(min_d, all_pairwise_ged_cache[c][ch]);
                if (min_d > best_min_dist) { best_min_dist = min_d; best_idx = c; }
            }
            if (best_idx == -1) break;
            chosen_mask_indices_greedy.push_back(best_idx);
            is_chosen[best_idx] = true;
        }
        while ((int)chosen_mask_indices_greedy.size() < M)
            chosen_mask_indices_greedy.push_back(chosen_mask_indices_greedy.empty() ? 0 : chosen_mask_indices_greedy[0]);

        G_ADJS_CHOSEN_GED.resize(M);
        for (int k = 0; k < M; ++k) {
            uint16_t mask = 0;
            if (k < (int)chosen_mask_indices_greedy.size() &&
                chosen_mask_indices_greedy[k] < (int)available_canonical_masks.size())
                mask = available_canonical_masks[chosen_mask_indices_greedy[k]];
            bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(mask, N_ACTUAL, tmp);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    G_ADJS_CHOSEN_GED[k][r][c] = tmp[r][c];
            std::string s = "";
            for (int b = 0; b < L_ACTUAL; ++b)
                s += ((mask >> b) & 1) ? '1' : '0';
            std::cout << s << "\n";
        }

    } else {
        // DEGREE_SEQ strategy: create graphs with distinct degree sequences
        // Use "lexicographic edge filling" to create highly non-uniform degree distributions
        G_ADJ_FLAT.resize(M);
        G_SORTED_DEG.resize(M);

        // Target edge counts: evenly spaced
        std::vector<int> target_edges(M);
        if (M == 1) {
            target_edges[0] = L_ACTUAL / 2;
        } else {
            for (int k = 0; k < M; ++k)
                target_edges[k] = (int)std::round((double)k * L_ACTUAL / (M - 1.0));
            for (int k = 1; k < M; ++k)
                target_edges[k] = std::max(target_edges[k], target_edges[k-1] + 1);
            for (int k = 0; k < M; ++k)
                target_edges[k] = std::max(0, std::min(L_ACTUAL, target_edges[k]));
        }

        for (int k = 0; k < M; ++k) {
            int E = target_edges[k];
            G_ADJ_FLAT[k].assign(L_ACTUAL, false);

            // Lexicographic fill: add edges in order (0,1),(0,2),...,(0,N-1),(1,2),...
            // This creates maximally non-uniform degree sequences
            // vertex 0 gets degree min(E, N-1), vertex 1 gets degree min(remaining, N-2), etc.
            int remaining = E;
            std::vector<int> deg(N_ACTUAL, 0);
            int idx = 0;
            for (int i = 0; i < N_ACTUAL && remaining > 0; ++i) {
                for (int j = i + 1; j < N_ACTUAL && remaining > 0; ++j) {
                    // Compute flat index for (i,j)
                    int flat_idx = i * (2*N_ACTUAL - i - 3) / 2 + j - 1;
                    G_ADJ_FLAT[k][flat_idx] = true;
                    deg[i]++;
                    deg[j]++;
                    remaining--;
                }
            }

            // Compute sorted degree sequence (decreasing)
            G_SORTED_DEG[k] = deg;
            std::sort(G_SORTED_DEG[k].begin(), G_SORTED_DEG[k].end(), std::greater<int>());

            // Output graph string
            std::string s(L_ACTUAL, '0');
            for (int i = 0; i < L_ACTUAL; ++i)
                if (G_ADJ_FLAT[k][i]) s[i] = '1';
            std::cout << s << "\n";
