            std::vector<int> h_deg(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) { h_deg[i]++; h_deg[j]++; }

            // Sorted degree sequence of H (decreasing)
            std::vector<int> h_sorted_deg = h_deg;
            std::sort(h_sorted_deg.begin(), h_sorted_deg.end(), std::greater<int>());

