                double score = 0;
                for (int i = 0; i < N_ACTUAL; ++i) {
                    double expected_deg = G_SORTED_DEG[j][i] * (1.0 - 2.0*eps) + (N_ACTUAL - 1) * eps;
                    double diff = h_sorted_deg[i] - expected_deg;
