                }
                if (score < best_score) { best_score = score; best_j = j; }
            }

            // Refine with Hamming distance using degree-rank alignment
            // Sort H vertices by degree (decreasing)
            std::vector<int> h_order(N_ACTUAL);
            std::iota(h_order.begin(), h_order.end(), 0);
            std::sort(h_order.begin(), h_order.end(),
                [&](int a, int b) { return h_deg[a] > h_deg[b] || (h_deg[a] == h_deg[b] && a < b); });

            // Get top candidates from degree-seq matching
            std::vector<std::pair<double, int>> cand_scores;
            for (int j = 0; j < M; ++j) {
                double score = 0;
                for (int i = 0; i < N_ACTUAL; ++i) {
                    double expected_deg = G_SORTED_DEG[j][i] * (1.0 - 2.0*eps) + (N_ACTUAL - 1) * eps;
                    double diff = h_sorted_deg[i] - expected_deg;
                    score += diff * diff;
                }
                cand_scores.push_back({score, j});
            }
            std::sort(cand_scores.begin(), cand_scores.end());

            int num_refine = std::min(3, (int)cand_scores.size());
            int final_best_j = cand_scores[0].second;
            int final_min_hamming = L_ACTUAL + 1;

            for (int ci = 0; ci < num_refine; ++ci) {
                int j = cand_scores[ci].second;

                // Build permutation from degree ranking
                // G_j vertices sorted by degree (decreasing)
                std::vector<int> g_order(N_ACTUAL);
                std::iota(g_order.begin(), g_order.end(), 0);
                // Compute G_j degrees from flat adjacency
                std::vector<int> gj_deg(N_ACTUAL, 0);
                int idx = 0;
                for (int ii = 0; ii < N_ACTUAL; ++ii)
                    for (int jj = ii + 1; jj < N_ACTUAL; ++jj) {
                        if (G_ADJ_FLAT[j][idx]) { gj_deg[ii]++; gj_deg[jj]++; }
                        idx++;
                    }
                std::sort(g_order.begin(), g_order.end(),
                    [&](int a, int b) { return gj_deg[a] > gj_deg[b] || (gj_deg[a] == gj_deg[b] && a < b); });

                // perm[g_vertex] = h_vertex (rank-matching)
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r)
                    perm[g_order[r]] = h_order[r];

                int ham = compute_hamming_perm(G_ADJ_FLAT[j], perm, N_ACTUAL);

                // Local search: swap pairs to reduce Hamming
                bool improved = true;
                int passes = 5;
                while (improved && passes-- > 0) {
                    improved = false;
                    for (int a = 0; a < N_ACTUAL; ++a) {
                        for (int b = a + 1; b < N_ACTUAL; ++b) {
                            int delta = compute_swap_delta(G_ADJ_FLAT[j], perm, a, b, N_ACTUAL);
                            if (delta < 0) {
                                std::swap(perm[a], perm[b]);
                                ham += delta;
                                improved = true;
                            }
                        }
                    }
                }

                if (ham < final_min_hamming) {
                    final_min_hamming = ham;
                    final_best_j = j;
                }
            }

            std::cout << final_best_j << "\n";
        }
        std::cout.flush();
    }
    return 0;
}
