            if (k < (int)chosen_mask_indices_greedy.size() &&
                chosen_mask_indices_greedy[k] < (int)available_canonical_masks.size())
                mask = available_canonical_masks[chosen_mask_indices_greedy[k]];
            bool tmp[N_MAX_GED_CAP][N_MAX_GED_CAP];
            mask_to_adj_matrix_small_N(mask, N_ACTUAL, tmp);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    G_ADJS_CHOSEN_GED[k][r][c] = tmp[r][c];
            std::string s = "";
            for (int b = 0; b < L_ACTUAL; ++b)
                s += ((mask >> b) & 1) ? '1' : '0';
            std::cout << s << "\n";
        }

    } else {
        // DEGREE_SEQ strategy with lexicographic fill
        G_ADJ_FLAT.resize(M);
        G_DEG.resize(M);
        G_DEG_ORDER.resize(M);

        std::vector<int> target_edges(M);
        if (M == 1) {
            target_edges[0] = L_ACTUAL / 2;
        } else {
            for (int k = 0; k < M; ++k)
                target_edges[k] = (int)std::round((double)k * L_ACTUAL / (M - 1.0));
            for (int k = 1; k < M; ++k)
                target_edges[k] = std::max(target_edges[k], target_edges[k-1] + 1);
            for (int k = 0; k < M; ++k)
                target_edges[k] = std::max(0, std::min(L_ACTUAL, target_edges[k]));
        }

        for (int k = 0; k < M; ++k) {
            int E = target_edges[k];
            G_ADJ_FLAT[k].assign(L_ACTUAL, false);
            G_DEG[k].assign(N_ACTUAL, 0);

            // Lexicographic fill
            int remaining = E;
            int idx = 0;
            for (int i = 0; i < N_ACTUAL && remaining > 0; ++i) {
                for (int j = i + 1; j < N_ACTUAL && remaining > 0; ++j) {
                    G_ADJ_FLAT[k][idx] = true;
                    G_DEG[k][i]++;
                    G_DEG[k][j]++;
                    remaining--;
                    idx++;
                }
                if (remaining > 0) {
                    // skip to next row start
                    // Actually idx already incremented naturally since inner loop goes j=i+1..N-1
                }
            }

            // Sort vertices by degree (decreasing), tiebreak by index
            G_DEG_ORDER[k].resize(N_ACTUAL);
            std::iota(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(), 0);
            std::sort(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(),
                [&](int a, int b) { return G_DEG[k][a] > G_DEG[k][b] || (G_DEG[k][a] == G_DEG[k][b] && a < b); });

            std::string s(L_ACTUAL, '0');
            for (int i = 0; i < L_ACTUAL; ++i)
                if (G_ADJ_FLAT[k][i]) s[i] = '1';
            std::cout << s << "\n";
        }
    }
    std::cout.flush();

    // Query phase
    for (int q = 0; q < 100; ++q) {
        std::string h_str;
        std::cin >> h_str;

        if (current_strategy == Strategy::GED) {
            string_to_adj_matrix_query(h_str, N_ACTUAL);
            int best_j = 0, min_dist = L_ACTUAL + 1;
            for (int j = 0; j < M; ++j) {
                int d = min_edit_distance_all_perms(G_ADJS_CHOSEN_GED[j]);
                if (d < min_dist) { min_dist = d; best_j = j; }
                if (min_dist == 0) break;
            }
            std::cout << best_j << "\n";

        } else {
            auto query_start = std::chrono::high_resolution_clock::now();

            string_to_adj_matrix_query(h_str, N_ACTUAL);

            // Compute H's degrees
            std::vector<int> h_deg(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) { h_deg[i]++; h_deg[j]++; }

            // Sort H vertices by degree (decreasing)
            std::vector<int> h_order(N_ACTUAL);
            std::iota(h_order.begin(), h_order.end(), 0);
            std::sort(h_order.begin(), h_order.end(),
                [&](int a, int b) { return h_deg[a] > h_deg[b] || (h_deg[a] == h_deg[b] && a < b); });

            // Sorted degree sequence
            std::vector<int> h_sorted_deg(N_ACTUAL);
            for (int r = 0; r < N_ACTUAL; ++r) h_sorted_deg[r] = h_deg[h_order[r]];

            // Score each candidate by expected degree-sequence L2 distance
            std::vector<std::pair<double, int>> cand_scores;
            for (int j = 0; j < M; ++j) {
                double score = 0;
                for (int r = 0; r < N_ACTUAL; ++r) {
                    double expected = G_DEG[j][G_DEG_ORDER[j][r]] * (1.0 - 2.0*eps) + (N_ACTUAL-1)*eps;
                    double diff = h_sorted_deg[r] - expected;
                    score += diff * diff;
                }
                cand_scores.push_back({score, j});
            }
            std::sort(cand_scores.begin(), cand_scores.end());

            // Time budget per query: ~40ms
            double time_budget_ms = 40.0;
            int num_refine = std::min(5, (int)cand_scores.size());
            int final_best_j = cand_scores[0].second;
            int final_min_hamming = L_ACTUAL + 1;

            for (int ci = 0; ci < num_refine; ++ci) {
                auto now = std::chrono::high_resolution_clock::now();
                double elapsed_ms = std::chrono::duration<double, std::milli>(now - query_start).count();
                if (elapsed_ms > time_budget_ms && ci > 0) break;

                int j = cand_scores[ci].second;

                // Build permutation: rank-match G_j to H
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r)
                    perm[G_DEG_ORDER[j][r]] = h_order[r];

                int ham = compute_hamming_perm(G_ADJ_FLAT[j], perm, N_ACTUAL);

                // Local search: greedy first-improvement swaps
                bool improved = true;
                int max_passes = 3;
                while (improved && max_passes-- > 0) {
                    improved = false;
                    auto now2 = std::chrono::high_resolution_clock::now();
                    double el = std::chrono::duration<double, std::milli>(now2 - query_start).count();
                    if (el > time_budget_ms) break;

                    for (int a = 0; a < N_ACTUAL && !improved; ++a) {
                        for (int b = a + 1; b < N_ACTUAL; ++b) {
                            int delta = compute_swap_delta_fast(G_ADJ_FLAT[j], perm, a, b, N_ACTUAL);
                            if (delta < 0) {
                                std::swap(perm[a], perm[b]);
                                ham += delta;
                                improved = true;
                                break;
                            }
                        }
                    }
                }

                if (ham < final_min_hamming) {
                    final_min_hamming = ham;
                    final_best_j = j;
                }
            }

            std::cout << final_best_j << "\n";
        }
        std::cout.flush();
    }
    return 0;
}
