std::vector<int> chosen_mask_indices_greedy;

// Degree-sequence strategy
std::vector<std::vector<bool>> G_ADJ_FLAT;
std::vector<std::vector<int>> G_DEG;
std::vector<std::vector<int>> G_DEG_ORDER;

int EDGE_IDX[100][100];

void precompute_edge_idx(int N) {
    int idx = 0;
    for (int i = 0; i < N; ++i)
        for (int j = i + 1; j < N; ++j) {
            EDGE_IDX[i][j] = EDGE_IDX[j][i] = idx;
            idx++;
        }
}

void string_to_adj_matrix_query(const std::string& s, int N_nodes) {
    int idx = 0;
    for (int i = 0; i < N_nodes; ++i) {
        CURRENT_GRAPH_ADJ_QUERY[i][i] = false;
        for (int j = i + 1; j < N_nodes; ++j) {
            bool val = (idx < (int)s.length()) ? (s[idx] == '1') : false;
            CURRENT_GRAPH_ADJ_QUERY[i][j] = CURRENT_GRAPH_ADJ_QUERY[j][i] = val;
            idx++;
        }
    }
}

int compute_hamming_perm(const std::vector<bool>& g_adj, const std::vector<int>& perm, int N) {
    int hamming = 0;
    int idx = 0;
    for (int i = 0; i < N; ++i) {
        for (int j = i + 1; j < N; ++j) {
            bool h_edge = CURRENT_GRAPH_ADJ_QUERY[perm[i]][perm[j]];
            if (h_edge != g_adj[idx]) hamming++;
            idx++;
        }
    }
    return hamming;
}

int compute_swap_delta_fast(const std::vector<bool>& g_adj, const std::vector<int>& perm, int a, int b, int N) {
    int delta = 0;
    int pa = perm[a], pb = perm[b];
    for (int x = 0; x < N; ++x) {
        if (x == a || x == b) continue;
        int px = perm[x];

        bool g_edge_ax = g_adj[EDGE_IDX[a][x]];
        delta += (CURRENT_GRAPH_ADJ_QUERY[pb][px] != g_edge_ax) - (CURRENT_GRAPH_ADJ_QUERY[pa][px] != g_edge_ax);

        bool g_edge_bx = g_adj[EDGE_IDX[b][x]];
        delta += (CURRENT_GRAPH_ADJ_QUERY[pa][px] != g_edge_bx) - (CURRENT_GRAPH_ADJ_QUERY[pb][px] != g_edge_bx);
    }
    return delta;
}

