            int remaining = E;
            int flat_idx = 0;
            for (int i = 0; i < N_ACTUAL && remaining > 0; ++i) {
                for (int j = i + 1; j < N_ACTUAL && remaining > 0; ++j) {
                    G_ADJ_FLAT[k][flat_idx] = true;
                    G_DEG[k][i]++;
                    G_DEG[k][j]++;
                    remaining--;
                    flat_idx++;
                }
                // flat_idx already at the right position for next i
            }

            G_DEG_ORDER[k].resize(N_ACTUAL);
            std::iota(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(), 0);
            std::sort(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(),
                [&](int a, int b) { return G_DEG[k][a] > G_DEG[k][b] || (G_DEG[k][a] == G_DEG[k][b] && a < b); });

