            string_to_adj_matrix_query(h_str, N_ACTUAL);

            // Compute H's degrees
            std::vector<int> h_deg(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ_QUERY[i][j]) { h_deg[i]++; h_deg[j]++; }

            // Sort H vertices by degree (decreasing)
            std::vector<int> h_order(N_ACTUAL);
            std::iota(h_order.begin(), h_order.end(), 0);
            std::sort(h_order.begin(), h_order.end(),
                [&](int a, int b) { return h_deg[a] > h_deg[b] || (h_deg[a] == h_deg[b] && a < b); });

            // Sorted degree sequence
            std::vector<int> h_sorted_deg(N_ACTUAL);
            for (int r = 0; r < N_ACTUAL; ++r) h_sorted_deg[r] = h_deg[h_order[r]];

            // Score each candidate by degree-sequence L2 distance
            std::vector<std::pair<double, int>> cand_scores;
            for (int j = 0; j < M; ++j) {
                double score = 0;
                for (int r = 0; r < N_ACTUAL; ++r) {
                    double expected = G_DEG[j][G_DEG_ORDER[j][r]] * (1.0 - 2.0*eps) + (N_ACTUAL-1)*eps;
                    double diff = h_sorted_deg[r] - expected;
                    score += diff * diff;
                }
                cand_scores.push_back({score, j});
            }
            std::sort(cand_scores.begin(), cand_scores.end());

            // Refine top candidates with Hamming + local search
            int num_refine = std::min(5, (int)cand_scores.size());
            int final_best_j = cand_scores[0].second;
            int final_min_hamming = L_ACTUAL + 1;

            for (int ci = 0; ci < num_refine; ++ci) {
                int j = cand_scores[ci].second;

                // Build permutation: rank-match
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r)
                    perm[G_DEG_ORDER[j][r]] = h_order[r];

                int ham = compute_hamming_perm(G_ADJ_FLAT[j], perm, N_ACTUAL);

                // Local search: best-improvement passes
                bool improved = true;
                int max_passes = 5;
                while (improved && max_passes-- > 0) {
                    improved = false;
                    for (int a = 0; a < N_ACTUAL; ++a) {
                        for (int b = a + 1; b < N_ACTUAL; ++b) {
                            int delta = compute_swap_delta_fast(G_ADJ_FLAT[j], perm, a, b, N_ACTUAL);
                            if (delta < 0) {
                                std::swap(perm[a], perm[b]);
                                ham += delta;
                                improved = true;
                            }
                        }
                    }
                }

                if (ham < final_min_hamming) {
                    final_min_hamming = ham;
                    final_best_j = j;
                }
            }

            std::cout << final_best_j << "\n";
        }
        std::cout.flush();
    }
    return 0;
}
