    if (current_strategy == Strategy::GED_BAYES) {
        PERM_VEC.resize(N_ACTUAL);
        CANON_P_PERM.resize(N_ACTUAL);

        if (N_ACTUAL == 6) available_canonical_masks = PRECOMPUTED_CANONICAL_MASKS_N6;
