uint16_t adj_to_mask_perm(int N, const bool adj[][N_MAX_GED], const std::vector<int>& p) {
    uint16_t mask = 0;
    int bit_idx = 0;
    for (int i = 0; i < N; ++i)
        for (int j = i + 1; j < N; ++j) {
            if (adj[p[i]][p[j]]) mask |= (1U << bit_idx);
            bit_idx++;
        }
    return mask;
}

uint16_t get_canonical_mask(uint16_t mask_val) {
    if (L_ACTUAL == 0) return 0;
    mask_to_adj_matrix(mask_val, N_ACTUAL, CANON_TMP_ADJ);
    std::iota(CANON_P_PERM.begin(), CANON_P_PERM.end(), 0);
    uint16_t min_mask = adj_to_mask_perm(N_ACTUAL, CANON_TMP_ADJ, CANON_P_PERM);
    while (std::next_permutation(CANON_P_PERM.begin(), CANON_P_PERM.end()))
        min_mask = std::min(min_mask, adj_to_mask_perm(N_ACTUAL, CANON_TMP_ADJ, CANON_P_PERM));
    return min_mask;
}

int hamming_one_perm_ged(const std::array<std::array<bool, N_MAX_GED>, N_MAX_GED>& g_adj) {
    int diff = 0;
    for (int i = 0; i < N_ACTUAL; ++i)
        for (int j = i + 1; j < N_ACTUAL; ++j)
            if (CURRENT_GRAPH_ADJ[PERM_VEC[i]][PERM_VEC[j]] != g_adj[i][j])
                diff++;
    return diff;
}

int min_edit_distance(const std::array<std::array<bool, N_MAX_GED>, N_MAX_GED>& g_adj) {
    if (L_ACTUAL == 0) return 0;
    std::iota(PERM_VEC.begin(), PERM_VEC.end(), 0);
    int min_d = L_ACTUAL + 1;
    do {
        int d = hamming_one_perm_ged(g_adj);
        min_d = std::min(min_d, d);
        if (min_d == 0) break;
    } while (std::next_permutation(PERM_VEC.begin(), PERM_VEC.end()));
    return min_d;
}

std::vector<uint16_t> available_canonical_masks;
std::vector<std::vector<int>> pairwise_ged;
std::map<uint16_t, int> mask_to_idx;
std::vector<int> chosen_indices;

// Degree-local-search strategy
std::vector<std::vector<bool>> G_ADJ_FLAT;
std::vector<std::vector<int>> G_DEG;
std::vector<std::vector<int>> G_DEG_ORDER;
int EDGE_IDX[100][100];

void precompute_edge_idx(int N) {
    int idx = 0;
    for (int i = 0; i < N; ++i)
        for (int j = i + 1; j < N; ++j) {
            EDGE_IDX[i][j] = EDGE_IDX[j][i] = idx;
            idx++;
        }
}

int compute_hamming_perm(const std::vector<bool>& g_adj, const std::vector<int>& perm, int N) {
    int hamming = 0;
    int idx = 0;
    for (int i = 0; i < N; ++i)
        for (int j = i + 1; j < N; ++j) {
            if (CURRENT_GRAPH_ADJ[perm[i]][perm[j]] != g_adj[idx]) hamming++;
            idx++;
        }
    return hamming;
}

int compute_swap_delta(const std::vector<bool>& g_adj, const std::vector<int>& perm, int a, int b, int N) {
    int delta = 0;
    int pa = perm[a], pb = perm[b];
    for (int x = 0; x < N; ++x) {
        if (x == a || x == b) continue;
        int px = perm[x];
        bool g_ax = g_adj[EDGE_IDX[a][x]];
        delta += (CURRENT_GRAPH_ADJ[pb][px] != g_ax) - (CURRENT_GRAPH_ADJ[pa][px] != g_ax);
        bool g_bx = g_adj[EDGE_IDX[b][x]];
        delta += (CURRENT_GRAPH_ADJ[pa][px] != g_bx) - (CURRENT_GRAPH_ADJ[pb][px] != g_bx);
    }
    return delta;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    unsigned int seed_val = std::chrono::duration_cast<std::chrono::nanoseconds>(
        std::chrono::high_resolution_clock::now().time_since_epoch()).count();
    RND_ENGINE.seed(seed_val);

    int M;
    double eps;
    std::cin >> M >> eps;

    int N_for_GED;
    if (M <= 11) N_for_GED = 4;
    else if (M <= 34) N_for_GED = 5;
    else N_for_GED = 6;

    // Use Bayesian GED for eps <= 0.25 (where N=6 Bayesian can still decode well)
    // The Bayesian approach is strictly better than min-distance and handles moderate noise
    if (M <= 156 && eps <= 0.25) {
        current_strategy = Strategy::GED_BAYES;
        N_ACTUAL = N_for_GED;
    } else {
        current_strategy = Strategy::DEGREE_LOCAL_SEARCH;
        double denom = std::max(0.05, 1.0 - 2.0*eps);
        double C = 3.0;
        double L_needed = C*C*(M-1.0)*(M-1.0)*eps*(1.0-eps)/(denom*denom);
        int N_candidate = (int)std::ceil((1.0 + std::sqrt(1.0 + 8.0*L_needed)) / 2.0);
        N_candidate = std::max(N_candidate, 10);
        N_candidate = std::min(N_candidate, 100);
        N_ACTUAL = N_candidate;
    }

    N_ACTUAL = std::max(4, std::min(100, N_ACTUAL));
    L_ACTUAL = N_ACTUAL * (N_ACTUAL - 1) / 2;
    precompute_edge_idx(N_ACTUAL);
    std::cout << N_ACTUAL << "\n";

    if (current_strategy == Strategy::GED_BAYES) {
        PERM_VEC.resize(N_ACTUAL);
        CANON_P_PERM.resize(N_ACTUAL);

        if (N_ACTUAL == 6) available_canonical_masks = PRECOMPUTED_CANONICAL_MASKS_N6;
        else {
            std::set<uint16_t> unique_masks;
            for (unsigned int i = 0; i < (1U << L_ACTUAL); ++i)
                unique_masks.insert(get_canonical_mask(static_cast<uint16_t>(i)));
            available_canonical_masks.assign(unique_masks.begin(), unique_masks.end());
        }

        int num_isos = available_canonical_masks.size();
        mask_to_idx.clear();
        for (int i = 0; i < num_isos; ++i) mask_to_idx[available_canonical_masks[i]] = i;

        // Pairwise GED for graph selection
        pairwise_ged.assign(num_isos, std::vector<int>(num_isos, 0));
        std::array<std::array<bool, N_MAX_GED>, N_MAX_GED> g_tmp;
        for (int i = 0; i < num_isos; ++i) {
            bool adj_i[N_MAX_GED][N_MAX_GED];
            mask_to_adj_matrix(available_canonical_masks[i], N_ACTUAL, adj_i);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    CURRENT_GRAPH_ADJ[r][c] = adj_i[r][c];
            for (int j = i + 1; j < num_isos; ++j) {
                bool adj_j[N_MAX_GED][N_MAX_GED];
                mask_to_adj_matrix(available_canonical_masks[j], N_ACTUAL, adj_j);
                for (int r = 0; r < N_ACTUAL; ++r)
                    for (int c = 0; c < N_ACTUAL; ++c)
                        g_tmp[r][c] = adj_j[r][c];
                pairwise_ged[i][j] = pairwise_ged[j][i] = min_edit_distance(g_tmp);
            }
        }

        // Greedy max-min selection
        chosen_indices.clear();
        std::vector<bool> is_chosen(num_isos, false);
        if (mask_to_idx.count(0)) {
            chosen_indices.push_back(mask_to_idx[0]);
            is_chosen[mask_to_idx[0]] = true;
        }
        if (L_ACTUAL > 0 && (int)chosen_indices.size() < M) {
            uint16_t comp = (1U << L_ACTUAL) - 1;
            uint16_t canon = get_canonical_mask(comp);
            if (mask_to_idx.count(canon) && !is_chosen[mask_to_idx[canon]]) {
                chosen_indices.push_back(mask_to_idx[canon]);
                is_chosen[mask_to_idx[canon]] = true;
            }
        }
        while ((int)chosen_indices.size() < M && (int)chosen_indices.size() < num_isos) {
            int best = -1, best_d = -1;
            for (int c = 0; c < num_isos; ++c) {
                if (is_chosen[c]) continue;
                int min_d = L_ACTUAL + 1;
                for (int ch : chosen_indices)
                    min_d = std::min(min_d, pairwise_ged[c][ch]);
                if (min_d > best_d) { best_d = min_d; best = c; }
            }
            if (best == -1) break;
            chosen_indices.push_back(best);
            is_chosen[best] = true;
        }
        while ((int)chosen_indices.size() < M)
            chosen_indices.push_back(chosen_indices[0]);

        G_ADJS_GED.resize(M);
        for (int k = 0; k < M; ++k) {
            uint16_t mask = available_canonical_masks[chosen_indices[k]];
            bool tmp[N_MAX_GED][N_MAX_GED];
            mask_to_adj_matrix(mask, N_ACTUAL, tmp);
            for (int r = 0; r < N_ACTUAL; ++r)
                for (int c = 0; c < N_ACTUAL; ++c)
                    G_ADJS_GED[k][r][c] = tmp[r][c];
            std::string s = "";
            for (int b = 0; b < L_ACTUAL; ++b)
                s += ((mask >> b) & 1) ? '1' : '0';
            std::cout << s << "\n";
        }

    } else {
        // DEGREE_LOCAL_SEARCH with lex-fill encoding
        G_ADJ_FLAT.resize(M);
        G_DEG.resize(M);
        G_DEG_ORDER.resize(M);

        std::vector<int> target_edges(M);
        if (M == 1) {
            target_edges[0] = L_ACTUAL / 2;
        } else {
            for (int k = 0; k < M; ++k)
                target_edges[k] = (int)std::round((double)k * L_ACTUAL / (M - 1.0));
            for (int k = 1; k < M; ++k)
                target_edges[k] = std::max(target_edges[k], target_edges[k-1] + 1);
            for (int k = 0; k < M; ++k)
                target_edges[k] = std::max(0, std::min(L_ACTUAL, target_edges[k]));
        }

        for (int k = 0; k < M; ++k) {
            int E = target_edges[k];
            G_ADJ_FLAT[k].assign(L_ACTUAL, false);
            G_DEG[k].assign(N_ACTUAL, 0);
            int remaining = E, flat_idx = 0;
            for (int i = 0; i < N_ACTUAL && remaining > 0; ++i)
                for (int j = i + 1; j < N_ACTUAL && remaining > 0; ++j) {
                    G_ADJ_FLAT[k][flat_idx] = true;
                    G_DEG[k][i]++; G_DEG[k][j]++;
                    remaining--; flat_idx++;
                }
            G_DEG_ORDER[k].resize(N_ACTUAL);
            std::iota(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(), 0);
            std::sort(G_DEG_ORDER[k].begin(), G_DEG_ORDER[k].end(),
                [&](int a, int b) { return G_DEG[k][a] > G_DEG[k][b] || (G_DEG[k][a] == G_DEG[k][b] && a < b); });
            std::string s(L_ACTUAL, '0');
            for (int i = 0; i < L_ACTUAL; ++i)
                if (G_ADJ_FLAT[k][i]) s[i] = '1';
            std::cout << s << "\n";
        }
    }
    std::cout.flush();

    // ========== Query phase ==========
    if (current_strategy == Strategy::GED_BAYES) {
        double log_ratio = (eps < 1e-9) ? -30.0 : (eps > 1.0-1e-9) ? 30.0 : std::log(eps/(1.0-eps));

        for (int q = 0; q < 100; ++q) {
            std::string h_str;
            std::cin >> h_str;
            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                CURRENT_GRAPH_ADJ[i][i] = false;
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    CURRENT_GRAPH_ADJ[i][j] = CURRENT_GRAPH_ADJ[j][i] = (h_str[idx++] == '1');
            }

            int best_j = 0;
            double best_ll = -1e18;
            for (int j = 0; j < M; ++j) {
                std::iota(PERM_VEC.begin(), PERM_VEC.end(), 0);
                double max_val = -1e18;
                std::vector<double> vals;
                vals.reserve(720);
                do {
                    int d = hamming_one_perm_ged(G_ADJS_GED[j]);
                    double val = d * log_ratio;
                    vals.push_back(val);
                    if (val > max_val) max_val = val;
                } while (std::next_permutation(PERM_VEC.begin(), PERM_VEC.end()));
                double sum_exp = 0;
                for (double v : vals) sum_exp += std::exp(v - max_val);
                double ll = max_val + std::log(sum_exp);
                if (ll > best_ll) { best_ll = ll; best_j = j; }
            }
            std::cout << best_j << "\n";
            std::cout.flush();
        }

    } else {
        // Degree-sequence + local search decoding
        for (int q = 0; q < 100; ++q) {
            std::string h_str;
            std::cin >> h_str;

            int idx = 0;
            for (int i = 0; i < N_ACTUAL; ++i) {
                CURRENT_GRAPH_ADJ[i][i] = false;
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    CURRENT_GRAPH_ADJ[i][j] = CURRENT_GRAPH_ADJ[j][i] = (h_str[idx++] == '1');
            }

            // H degrees
            std::vector<int> h_deg(N_ACTUAL, 0);
            for (int i = 0; i < N_ACTUAL; ++i)
                for (int j = i + 1; j < N_ACTUAL; ++j)
                    if (CURRENT_GRAPH_ADJ[i][j]) { h_deg[i]++; h_deg[j]++; }

            std::vector<int> h_order(N_ACTUAL);
            std::iota(h_order.begin(), h_order.end(), 0);
            std::sort(h_order.begin(), h_order.end(),
                [&](int a, int b) { return h_deg[a] > h_deg[b] || (h_deg[a] == h_deg[b] && a < b); });

            // Degree-seq L2 scoring
            std::vector<int> h_sorted_deg(N_ACTUAL);
            for (int r = 0; r < N_ACTUAL; ++r) h_sorted_deg[r] = h_deg[h_order[r]];

            std::vector<std::pair<double, int>> cand_scores;
            for (int j = 0; j < M; ++j) {
                double score = 0;
                for (int r = 0; r < N_ACTUAL; ++r) {
                    double expected = G_DEG[j][G_DEG_ORDER[j][r]] * (1.0-2.0*eps) + (N_ACTUAL-1)*eps;
                    double diff = h_sorted_deg[r] - expected;
                    score += diff * diff;
                }
                cand_scores.push_back({score, j});
            }
            std::sort(cand_scores.begin(), cand_scores.end());

            int num_refine = std::min(5, (int)cand_scores.size());
            int final_best_j = cand_scores[0].second;
            int final_min_hamming = L_ACTUAL + 1;

            for (int ci = 0; ci < num_refine; ++ci) {
                int j = cand_scores[ci].second;
                std::vector<int> perm(N_ACTUAL);
                for (int r = 0; r < N_ACTUAL; ++r)
                    perm[G_DEG_ORDER[j][r]] = h_order[r];

                int ham = compute_hamming_perm(G_ADJ_FLAT[j], perm, N_ACTUAL);

                bool improved = true;
                int max_passes = 5;
                while (improved && max_passes-- > 0) {
                    improved = false;
                    for (int a = 0; a < N_ACTUAL; ++a)
                        for (int b = a + 1; b < N_ACTUAL; ++b) {
                            int delta = compute_swap_delta(G_ADJ_FLAT[j], perm, a, b, N_ACTUAL);
                            if (delta < 0) {
                                std::swap(perm[a], perm[b]);
                                ham += delta;
                                improved = true;
                            }
                        }
                }
                if (ham < final_min_hamming) {
                    final_min_hamming = ham;
                    final_best_j = j;
                }
            }
            std::cout << final_best_j << "\n";
            std::cout.flush();
        }
    }
    return 0;
}
